    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');

        canvas.width = 360;
        canvas.height = 640;

        // 游戏状态
        let gameRunning = true;
        let score = 0;
        let lives = 3;

        // 玩家飞船
        const player = {
            x: canvas.width / 2 - 20,
            y: canvas.height - 60,
            width: 40,
            height: 40,
            speed: 5,
            dx: 0,
            dy: 0,
            color: 'cyan',
            lastShotTime: 0,
            shotCooldown: 200 // 射击冷却时间（毫秒）
        };

        // 子弹类型
        const BULLET_TYPE = {
            NORMAL: 'normal',
            HOMING: 'homing',
            FLAME: 'flame'
        };

        // 敌人类型
        const ENEMY_TYPE = {
            NORMAL: 'normal',
            ELITE: 'elite'
        };

        // 游戏元素数组
        const bullets = [];
        const enemies = [];
        const particles = []; // 爆炸粒子
        const powerUps = []; // 道具

        // 游戏变量
        let lastSpawnTime = 0;
        const spawnInterval = 1000; // 敌人生成间隔
        const maxEnemies = 10;

        // 道具掉落概率
        const powerUpDropChance = 0.1; // 10% 概率

        // 当前子弹类型
        let currentBulletType = BULLET_TYPE.NORMAL;
        let powerUpActiveTime = 0;
        const powerUpDuration = 10000; // 道具持续时间 10 秒

        // 图像资源（可选，这里用颜色代替）
        // const playerImage = new Image();
        // playerImage.src = 'player.png'; // 假设有图片
        // playerImage.onload = () => console.log('Player image loaded');

        // 事件监听
        document.addEventListener('keydown', keyDown);
        document.addEventListener('keyup', keyUp);

        // 移动端触摸控制
        let touchStartX = 0;
        let touchStartY = 0;
        let isTouching = false;

        canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            isTouching = true;
            touchStartX = e.touches[0].clientX;
            touchStartY = e.touches[0].clientY;
        });

        canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
            if (isTouching) {
                const touchX = e.touches[0].clientX;
                const touchY = e.touches[0].clientY;

                const rect = canvas.getBoundingClientRect();
                const scaleX = canvas.width / rect.width;
                const scaleY = canvas.height / rect.height;

                const canvasX = (touchX - rect.left) * scaleX;
                const canvasY = (touchY - rect.top) * scaleY;

                player.x = canvasX - player.width / 2;
                player.y = canvasY - player.height / 2;

                // 边界检查
                if (player.x < 0) player.x = 0;
                if (player.x + player.width > canvas.width) player.x = canvas.width - player.width;
                if (player.y < 0) player.y = 0;
                if (player.y + player.height > canvas.height) player.y = canvas.height - player.height;
            }
        });

        canvas.addEventListener('touchend', (e) => {
            e.preventDefault();
            isTouching = false;
        });


        function keyDown(e) {
            if (!gameRunning) return;
            if (e.key === 'ArrowRight' || e.key === 'd') {
                player.dx = player.speed;
            } else if (e.key === 'ArrowLeft' || e.key === 'a') {
                player.dx = -player.speed;
            } else if (e.key === 'ArrowUp' || e.key === 'w') {
                player.dy = -player.speed;
            } else if (e.key === 'ArrowDown' || e.key === 's') {
                player.dy = player.speed;
            } else if (e.key === ' ' && Date.now() - player.lastShotTime > player.shotCooldown) {
                shootBullet();
                player.lastShotTime = Date.now();
            }
        }

        function keyUp(e) {
            if (!gameRunning) return;
            if (
                e.key === 'ArrowRight' || e.key === 'd' ||
                e.key === 'ArrowLeft' || e.key === 'a'
            ) {
                player.dx = 0;
            }
            if (
                e.key === 'ArrowUp' || e.key === 'w' ||
                e.key === 'ArrowDown' || e.key === 's'
            ) {
                player.dy = 0;
            }
        }

        function shootBullet() {
            let bulletSpeed = 7;
            let bulletColor = 'lime';
            let damage = 1;
            let width = 6;
            let height = 12;

            if (currentBulletType === BULLET_TYPE.HOMING) {
                bulletColor = 'orange';
                width = 8;
                height = 8;
                damage = 1; // 追踪弹伤害同普通弹
            } else if (currentBulletType === BULLET_TYPE.FLAME) {
                bulletColor = 'red';
                width = 10;
                height = 20;
                damage = 2; // 火焰弹伤害更高
            }

            bullets.push({
                x: player.x + player.width / 2 - width / 2,
                y: player.y,
                width: width,
                height: height,
                speed: bulletSpeed,
                color: bulletColor,
                type: currentBulletType,
                damage: damage
            });
        }

        function drawPlayer() {
            ctx.fillStyle = player.color;
            ctx.fillRect(player.x, player.y, player.width, player.height);
            // 如果有图片，可以用 ctx.drawImage(playerImage, player.x, player.y, player.width, player.height);
        }

        function drawBullets() {
            bullets.forEach(bullet => {
                ctx.fillStyle = bullet.color;
                ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
            });
        }

        function drawEnemies() {
            enemies.forEach(enemy => {
                ctx.fillStyle = enemy.color;
                ctx.fillRect(enemy.x, enemy.y, enemy.width, enemy.height);
                // 绘制生命条
                if (enemy.type === ENEMY_TYPE.ELITE) {
                    const healthBarWidth = enemy.width;
                    const healthBarHeight = 3;
                    const healthBarY = enemy.y - healthBarHeight - 2;
                    ctx.fillStyle = 'gray';
                    ctx.fillRect(enemy.x, healthBarY, healthBarWidth, healthBarHeight);
                    ctx.fillStyle = 'lightgreen';
                    ctx.fillRect(enemy.x, healthBarY, healthBarWidth * (enemy.health / enemy.maxHealth), healthBarHeight);
                }
            });
        }

        function drawParticles() {
            particles.forEach(p => {
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                ctx.fill();
            });
        }

        function drawPowerUps() {
            powerUps.forEach(p => {
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                ctx.fill();
                ctx.fillStyle = 'white';
                ctx.font = '8px Arial';
                ctx.textAlign = 'center';
                ctx.fillText(p.type === BULLET_TYPE.HOMING ? 'H' : 'F', p.x, p.y + 3);
            });
        }

        function updatePlayer() {
            player.x += player.dx;
            player.y += player.dy;

            // 边界检查
            if (player.x < 0) player.x = 0;
            if (player.x + player.width > canvas.width) player.x = canvas.width - player.width;
            if (player.y < 0) player.y = 0;
            if (player.y + player.height > canvas.height) player.y = canvas.height - player.height;

            // 自动射击（如果不是触摸控制，且按键没有按住）
            if (!isTouching && player.dx === 0 && player.dy === 0 && Date.now() - player.lastShotTime > player.shotCooldown) {
                 shootBullet();
                 player.lastShotTime = Date.now();
            }
        }

        function updateBullets() {
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                bullet.y -= bullet.speed;

                if (bullet.type === BULLET_TYPE.HOMING) {
                    // 追踪最近的敌人
                    let closestEnemy = null;
                    let minDistance = Infinity;
                    enemies.forEach(enemy => {
                        const dist = Math.hypot(enemy.x + enemy.width / 2 - bullet.x, enemy.y + enemy.height / 2 - bullet.y);
                        if (dist < minDistance) {
                            minDistance = dist;
                            closestEnemy = enemy;
                        }
                    });

                    if (closestEnemy) {
                        const targetX = closestEnemy.x + closestEnemy.width / 2;
                        const targetY = closestEnemy.y + closestEnemy.height / 2;
                        const angle = Math.atan2(targetY - bullet.y, targetX - bullet.x);
                        bullet.x += Math.cos(angle) * bullet.speed * 0.5; // 追踪速度慢一点
                        bullet.y += Math.sin(angle) * bullet.speed * 0.5;
                    }
                }

                // 移除超出屏幕的子弹
                if (bullet.y < 0) {
                    bullets.splice(i, 1);
                }
            }
        }

        function updateEnemies() {
            // 生成敌人
            if (Date.now() - lastSpawnTime > spawnInterval && enemies.length < maxEnemies) {
                spawnEnemy();
                lastSpawnTime = Date.now();
            }

            for (let i = enemies.length - 1; i >= 0; i--) {
                const enemy = enemies[i];
                enemy.y += enemy.speed;

                // 敌人与玩家碰撞
                if (checkCollision(player, enemy)) {
                    lives--;
                    createExplosion(player.x + player.width / 2, player.y + player.height / 2, 'red');
                    resetPlayerPosition();
                    enemies.splice(i, 1);
                    updateGameInfo();
                    if (lives <= 0) {
                        gameOver();
                        return;
                    }
                    continue;
                }

                // 移除超出屏幕的敌人
                if (enemy.y > canvas.height) {
                    enemies.splice(i, 1);
                }
            }
        }

        function spawnEnemy() {
            const enemyType = Math.random() < 0.2 ? ENEMY_TYPE.ELITE : ENEMY_TYPE.NORMAL; // 20% 概率生成精英怪
            const enemyWidth = enemyType === ENEMY_TYPE.ELITE ? 40 : 30;
            const enemyHeight = enemyType === ENEMY_TYPE.ELITE ? 40 : 30;
            const enemyHealth = enemyType === ENEMY_TYPE.ELITE ? 2 : 1; // 精英怪需要打两下
            const enemyColor = enemyType === ENEMY_TYPE.ELITE ? 'purple' : 'green';
            const enemySpeed = enemyType === ENEMY_TYPE.ELITE ? 1.5 : 1;
            const enemyScore = enemyType === ENEMY_TYPE.ELITE ? 20 : 10;

            enemies.push({
                x: Math.random() * (canvas.width - enemyWidth),
                y: -enemyHeight, // 从屏幕上方生成
                width: enemyWidth,
                height: enemyHeight,
                speed: enemySpeed,
                color: enemyColor,
                type: enemyType,
                health: enemyHealth,
                maxHealth: enemyHealth, // 记录最大生命值用于血条
                score: enemyScore
            });
        }

        function updateParticles() {
            for (let i = particles.length - 1; i >= 0; i--) {
                const p = particles[i];
                p.x += p.vx;
                p.y += p.vy;
                p.alpha -= 0.02;
                if (p.alpha <= 0) {
                    particles.splice(i, 1);
                }
            }
        }

        function updatePowerUps() {
            for (let i = powerUps.length - 1; i >= 0; i--) {
                const p = powerUps[i];
                p.y += p.speed;

                // 道具与玩家碰撞
                if (checkCollision(player, p)) {
                    currentBulletType = p.type;
                    powerUpActiveTime = Date.now();
                    particles.splice(i, 1); // 移除道具
                    // 播放音效
                    // new Audio('powerup.mp3').play();
                }

                if (p.y > canvas.height + p.radius) {
                    powerUps.splice(i, 1);
                }
            }

            // 检查道具持续时间
            if (currentBulletType !== BULLET_TYPE.NORMAL && Date.now() - powerUpActiveTime > powerUpDuration) {
                currentBulletType = BULLET_TYPE.NORMAL;
            }
        }

        function checkCollision(obj1, obj2) {
            return (
                obj1.x < obj2.x + obj2.width &&
                obj1.x + obj1.width > obj2.x &&
                obj1.y < obj2.y + obj2.height &&
                obj1.y + obj1.height > obj2.y
            );
        }

        function detectCollisions() {
            // 子弹与敌人碰撞
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                for (let j = enemies.length - 1; j >= 0; j--) {
                    const enemy = enemies[j];
                    if (checkCollision(bullet, enemy)) {
                        enemy.health -= bullet.damage;
                        createExplosion(bullet.x, bullet.y, 'yellow', 5, 2); // 子弹击中效果

                        if (enemy.health <= 0) {
                            score += enemy.score;
                            createExplosion(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2, 'white');
                            // 掉落道具
                            if (Math.random() < powerUpDropChance) {
                                spawnPowerUp(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2);
                            }
                            enemies.splice(j, 1);
                        }
                        bullets.splice(i, 1); // 移除子弹
                        updateGameInfo();
                        break; // 一个子弹只能击中一个敌人
                    }
                }
            }
        }

        function createExplosion(x, y, color, count = 10, radius = 2) {
            for (let i = 0; i < count; i++) {
                particles.push({
                    x: x,
                    y: y,
                    vx: (Math.random() - 0.5) * 4,
                    vy: (Math.random() - 0.5) * 4,
                    radius: Math.random() * radius + 1,
                    color: color,
                    alpha: 1
                });
            }
        }

        function spawnPowerUp(x, y) {
            const type = Math.random() < 0.5 ? BULLET_TYPE.HOMING : BULLET_TYPE.FLAME;
            const color = type === BULLET_TYPE.HOMING ? 'orange' : 'red';
            powerUps.push({
                x: x,
                y: y,
                radius: 10,
                speed: 0.8,
                color: color,
                type: type
            });
        }

        function updateGameInfo() {
            document.getElementById('score').textContent = score;
            document.getElementById('lives').textContent = lives;
        }

        function resetPlayerPosition() {
            player.x = canvas.width / 2 - player.width / 2;
            player.y = canvas.height - 60;
            player.dx = 0;
            player.dy = 0;
        }

        function gameOver() {
            gameRunning = false;
            document.getElementById('final-score').textContent = score;
            document.getElementById('game-over-screen').style.display = 'flex';
        }

        function restartGame() {
            // 重置所有游戏状态
            score = 0;
            lives = 3;
            bullets.length = 0;
            enemies.length = 0;
            particles.length = 0;
            powerUps.length = 0;
            currentBulletType = BULLET_TYPE.NORMAL;
            powerUpActiveTime = 0;
            lastSpawnTime = 0;
            resetPlayerPosition();
            updateGameInfo();
            document.getElementById('game-over-screen').style.display = 'none';
            gameRunning = true;
            gameLoop(); // 重新开始游戏循环
        }

        function gameLoop() {
            if (!gameRunning) return;

            ctx.clearRect(0, 0, canvas.width, canvas.height); // 清空画布

            updatePlayer();
            updateBullets();
            updateEnemies();
            updateParticles();
            updatePowerUps();
            detectCollisions();

            drawPlayer();
            drawBullets();
            drawEnemies();
            drawParticles();
            drawPowerUps();

            requestAnimationFrame(gameLoop); // 循环调用
        }

        // 初始化
        updateGameInfo();
        gameLoop();
    </script>
</body>
</html>
